1	package bind
2	
3	import (
4		"bytes"
5		"crypto/rand"
6		"net/netip"
7		"testing"
8	
9		"github.com/7mind/wanbond/internal/config"
10		"github.com/7mind/wanbond/internal/fec"
11		"github.com/7mind/wanbond/internal/frame"
12		"github.com/7mind/wanbond/internal/telemetry"
13	)
